// Deferred outbox queue — envelopes pending dispatch + retry status.
// Generated by flowforge JTBD generator — do not edit by hand.
import * as React from "react";

import { adminApi, type AdminOutboxEnvelope } from "../api";

export interface OutboxQueueProps {
	grantedPermissions?: ReadonlyArray<string>;
}

function canRetry(granted: ReadonlyArray<string>): boolean {
	return granted.some((g) => g.endsWith(".outbox.retry"));
}

export function OutboxQueue(props: OutboxQueueProps): React.ReactElement {
	const granted: ReadonlyArray<string> = props.grantedPermissions ?? [];
	const [rows, setRows] = React.useState<ReadonlyArray<AdminOutboxEnvelope>>([]);
	const [error, setError] = React.useState<string | null>(null);
	const [busy, setBusy] = React.useState(false);
	const [retrying, setRetrying] = React.useState<string | null>(null);

	const load = React.useCallback(async () => {
		setBusy(true);
		setError(null);
		try {
			setRows(await adminApi.listOutbox());
		} catch (e: unknown) {
			setError(e instanceof Error ? e.message : "load failed");
		} finally {
			setBusy(false);
		}
	}, []);

	React.useEffect(() => {
		void load();
	}, [load]);

	const retry = React.useCallback(
		async (id: string) => {
			setRetrying(id);
			setError(null);
			try {
				await adminApi.retryOutbox(id);
				await load();
			} catch (e: unknown) {
				setError(e instanceof Error ? e.message : "retry failed");
			} finally {
				setRetrying(null);
			}
		},
		[load],
	);

	const allowed = canRetry(granted);

	return (
		<section aria-labelledby="outbox-heading">
			<h2 id="outbox-heading">Outbox queue</h2>
			<p className="ff-admin-hint">
				Envelopes the engine deferred to the outbox but the dispatcher hasn't
				delivered yet. Backed by <code>OutboxRegistry</code>{" "}
				(<code>flowforge-outbox-pg</code> on Postgres hosts). A non-zero attempt
				count + recent <code>last_error</code> means the dispatcher is
				back-off-throttled — review the error before forcing a retry.
			</p>
			{error ? (
				<p role="alert" className="ff-admin-error">
					{error}
				</p>
			) : null}
			<table className="ff-admin-table">
				<thead>
					<tr>
						<th scope="col">id</th>
						<th scope="col">tenant</th>
						<th scope="col">topic</th>
						<th scope="col">attempts</th>
						<th scope="col">next attempt</th>
						<th scope="col">last error</th>
						<th scope="col">action</th>
					</tr>
				</thead>
				<tbody>
					{rows.map((row) => (
						<tr key={row.id}>
							<td>
								<code>{row.id}</code>
							</td>
							<td>{row.tenant_id}</td>
							<td>
								<code>{row.topic}</code>
							</td>
							<td>{row.attempts}</td>
							<td>
								<time dateTime={row.next_attempt_at}>{row.next_attempt_at}</time>
							</td>
							<td>
								{row.last_error ? (
									<code className="ff-admin-error">{row.last_error}</code>
								) : (
									<em className="ff-admin-muted">none</em>
								)}
							</td>
							<td>
								<button
									type="button"
									disabled={!allowed || retrying === row.id || busy}
									onClick={() => void retry(row.id)}
									title={
										allowed
											? "Force retry now"
											: "Missing admin.<jtbd>.outbox.retry permission"
									}
								>
									{retrying === row.id ? "Retrying…" : "Retry now"}
								</button>
							</td>
						</tr>
					))}
					{rows.length === 0 && !busy ? (
						<tr>
							<td colSpan={7}>queue is empty</td>
						</tr>
					) : null}
				</tbody>
			</table>
		</section>
	);
}
